module RefModule(clk,reset,R,S,Out);input reset, clk, R, S;
	 output Out;
	 reg   obf_dataVal;

	 always @(posedge clk, negedge reset)
		if(!reset)
			obf_dataVal<=0;
		else if(R)
			obf_dataVal<=0;
		else if(S)
			obf_dataVal<=1;
		else 
			obf_dataVal<=obf_dataVal;

		assign Out=obf_dataVal;

	 endmodule
